{
    "level": "A2",
    "intro": "W tym temacie nauczysz się poprawnie tworzyć i stosować <strong>comparative</strong> oraz <strong>superlative</strong> przymiotników i przysłówków.",
    "rules": [
        {
            "label": "Base form",
            "color": "emerald",
            "text": "Opis bez porównania:",
            "example": "This road is narrow."
        },
        {
            "label": "Comparative",
            "color": "blue",
            "text": "Porównanie dwóch rzeczy z <em>than</em>:",
            "example": "This road is narrower than that one."
        },
        {
            "label": "Superlative",
            "color": "rose",
            "text": "Wyróżnienie jednego elementu z grupy z <em>the</em>:",
            "example": "This is the narrowest street in town."
        }
    ]
}

{
    "title": "1. Krótkie wyrazy (1-2 sylaby)",
    "intro": "W przypadku krótkich przymiotników dodajemy końcówki <code class=\"font-mono text-xs\">-er</code> / <code class=\"font-mono text-xs\">-est</code>:",
    "items": [
        {
            "label": "Ogólna zasada",
            "title": "-er / -est",
            "subtitle": "fast → faster → the fastest"
        },
        {
            "label": "Wyrazy kończące się na -y",
            "title": "-ier / -iest",
            "subtitle": "happy → happier → the happiest"
        },
        {
            "label": "Podwojenie spółgłoski",
            "title": "big → bigger",
            "subtitle": "Gdy wzór to: spółgłoska + samogłoska + spółgłoska"
        },
        {
            "label": "Wyrazy kończące się na -e",
            "title": "-r / -st",
            "subtitle": "large → larger → the largest"
        }
    ]
}

{
    "title": "2. Długie wyrazy i przysłówki",
    "sections": [
        {
            "label": "More / Most",
            "color": "emerald",
            "description": "Przymiotniki mające 3+ sylaby oraz większość przysłówków używają <strong>more / most</strong>.",
            "examples": [
                {
                    "en": "interesting → more interesting → the most interesting",
                    "ua": "interesujący"
                },
                {
                    "en": "quickly → more quickly → the most quickly",
                    "ua": "szybko"
                }
            ]
        },
        {
            "label": "Less / Least",
            "color": "rose",
            "description": "Dla znaczenia przeciwnego używamy <strong>less / least</strong>.",
            "examples": [
                {
                    "en": "dangerous → less dangerous → the least dangerous",
                    "ua": "niebezpieczny"
                }
            ]
        },
        {
            "label": "Wyrazy dwusylabowe",
            "color": "sky",
            "description": "Niektóre przymiotniki dwusylabowe dopuszczają obie formy, zwłaszcza te zakończone na <strong>-y</strong>, <strong>-ow</strong> lub <strong>-er</strong>:",
            "examples": [
                {
                    "en": "shallow → shallower / more shallow",
                    "ua": "płytki"
                },
                {
                    "en": "clever → cleverer / more clever",
                    "ua": "sprytny"
                }
            ]
        }
    ]
}

{
    "title": "3. Formy nieregularne",
    "intro": "Niektóre przymiotniki i przysłówki mają specjalne formy comparative i superlative:",
    "rows": [
        {
            "en": "good / well",
            "ua": "dobry / dobrze",
            "note": "better → the best"
        },
        {
            "en": "bad / badly",
            "ua": "zły / źle",
            "note": "worse → the worst"
        },
        {
            "en": "far",
            "ua": "daleko",
            "note": "farther/further → the farthest/furthest"
        },
        {
            "en": "little (amount)",
            "ua": "mało (ilość)",
            "note": "less → the least"
        },
        {
            "en": "many / much",
            "ua": "wiele / dużo",
            "note": "more → the most"
        }
    ],
    "warning": "💡 <em>Further</em> częściej oznacza „dodatkowy” albo „dalszy w czasie”, a <em>farther</em> zwykle odnosi się do fizycznej odległości."
}

{
    "title": "4. Wzmacnianie i osłabianie porównania",
    "sections": [
        {
            "label": "Wzmacnianie comparative",
            "color": "emerald",
            "description": "Przed comparative używaj <strong>much / way / a lot / far</strong>:",
            "examples": [
                {
                    "en": "This is much better than before.",
                    "ua": "To jest o wiele lepsze niż wcześniej."
                },
                {
                    "en": "He runs way faster than me.",
                    "ua": "On biega dużo szybciej ode mnie."
                }
            ]
        },
        {
            "label": "Wzmacnianie superlative",
            "color": "blue",
            "description": "Przed superlative używaj <strong>by far / easily</strong>:",
            "examples": [
                {
                    "en": "She is by far the best student.",
                    "ua": "Jest zdecydowanie najlepszą uczennicą."
                }
            ]
        },
        {
            "label": "Osłabienie różnicy",
            "color": "sky",
            "description": "Dla niewielkiej różnicy używaj <strong>slightly / a bit / a little</strong>:",
            "examples": [
                {
                    "en": "This is slightly cheaper.",
                    "ua": "To jest trochę tańsze."
                }
            ]
        }
    ]
}

{
    "title": "5. Konstrukcje porównawcze",
    "sections": [
        {
            "label": "As ... as",
            "color": "emerald",
            "description": "Dla równości używamy <strong>as + adjective/adverb + as</strong>:",
            "examples": [
                {
                    "en": "She is as tall as her brother.",
                    "ua": "Ona jest tak wysoka jak jej brat."
                },
                {
                    "en": "He runs as fast as me.",
                    "ua": "On biega tak szybko jak ja."
                }
            ]
        },
        {
            "label": "Not as/so ... as",
            "color": "rose",
            "description": "Dla nierówności używamy <strong>not as/so + adjective + as</strong>:",
            "examples": [
                {
                    "en": "This book is not as interesting as that one.",
                    "ua": "Ta książka nie jest tak interesująca jak tamta."
                }
            ]
        },
        {
            "label": "The + superlative + in/of",
            "color": "sky",
            "description": "Aby wyróżnić jeden element z grupy:",
            "examples": [
                {
                    "en": "He is the tallest in the class.",
                    "ua": "On jest najwyższy w klasie."
                },
                {
                    "en": "This is the most useful of all.",
                    "ua": "To jest najbardziej przydatne ze wszystkich."
                }
            ]
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Podwójne znaczniki porównania.",
            "wrong": "more better / the most fastest",
            "right": "✅ <span class=\"font-mono\">better / the fastest</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Brak <strong>the</strong> przed superlative.",
            "wrong": "He is tallest in the class.",
            "right": "✅ <span class=\"font-mono\">He is the tallest in the class.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła forma po <strong>than</strong>.",
            "wrong": "My car is more reliable than your.",
            "right": "✅ <span class=\"font-mono\">My car is more reliable than yours.</span>"
        }
    ]
}
